package app

import (
	"fmt"
	"sync"
	"unsafe"

	"github.com/AndroidGoLab/jni"
)

// Context wraps android.content.Context.
//
// This file is hand-maintained (not generated by javagen) because Context
// is the foundational type used by all generated server packages. javagen
// generates the Intent/Activity/PendingIntent types in this package; the
// Context type and its JNI class/method IDs live here separately.
type Context struct {
	VM  *jni.VM
	Obj *jni.GlobalRef
}

var (
	ctxInitOnce                sync.Once
	ctxInitErr                 error
	clsContext                 *jni.GlobalRef
	midContextGetSystemService jni.MethodID
)

func ensureContextInit(env *jni.Env) error {
	ctxInitOnce.Do(func() {
		var c *jni.Class
		c, ctxInitErr = env.FindClass("android/content/Context")
		if ctxInitErr != nil {
			ctxInitErr = fmt.Errorf("find class android.content.Context: %w", ctxInitErr)
			return
		}
		clsContext = env.NewGlobalRef(&c.Object)

		midContextGetSystemService, ctxInitErr = env.GetMethodID(
			(*jni.Class)(unsafe.Pointer(clsContext)),
			"getSystemService",
			"(Ljava/lang/String;)Ljava/lang/Object;",
		)
		if ctxInitErr != nil {
			ctxInitErr = fmt.Errorf("get method android.content.Context.getSystemService: %w", ctxInitErr)
		}
	})
	return ctxInitErr
}

// Close releases the global reference to the underlying Java object.
// After Close, the Context must not be used.
func (m *Context) Close() {
	if m.Obj != nil {
		m.VM.Do(func(env *jni.Env) error {
			env.DeleteGlobalRef(m.Obj)
			m.Obj = nil
			return nil
		})
	}
}

// PackageManager calls android.content.Context.getPackageManager().
func (m *Context) PackageManager() (*jni.Object, error) {
	var result *jni.Object
	var callErr error
	m.VM.Do(func(env *jni.Env) error {
		if err := ensureContextInit(env); err != nil {
			callErr = err
			return err
		}
		mid, err := env.GetMethodID(
			(*jni.Class)(unsafe.Pointer(clsContext)),
			"getPackageManager",
			"()Landroid/content/pm/PackageManager;",
		)
		if err != nil {
			callErr = fmt.Errorf("get getPackageManager: %w", err)
			return callErr
		}
		result, callErr = env.CallObjectMethod(m.Obj, mid)
		return callErr
	})
	return result, callErr
}

// ContentResolver calls android.content.Context.getContentResolver().
func (m *Context) ContentResolver() *jni.Object {
	var result *jni.Object
	m.VM.Do(func(env *jni.Env) error {
		if err := ensureContextInit(env); err != nil {
			return err
		}
		mid, err := env.GetMethodID(
			(*jni.Class)(unsafe.Pointer(clsContext)),
			"getContentResolver",
			"()Landroid/content/ContentResolver;",
		)
		if err != nil {
			return err
		}
		result, _ = env.CallObjectMethod(m.Obj, mid)
		return nil
	})
	return result
}

// GetSystemService calls android.content.Context.getSystemService.
func (m *Context) GetSystemService(name string) (*jni.Object, error) {
	var result *jni.Object
	var callErr error
	m.VM.Do(func(env *jni.Env) error {
		if err := ensureContextInit(env); err != nil {
			callErr = err
			return err
		}
		jName, err := env.NewStringUTF(name)
		if err != nil {
			return err
		}

		result, callErr = env.CallObjectMethod(
			m.Obj,
			midContextGetSystemService, jni.ObjectValue(&jName.Object),
		)
		return callErr
	})
	return result, callErr
}
